// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 3000
#define MAX_M 4500000

// Structure to represent a graph edge
typedef struct Edge {
    int u, v;
} Edge;

// Function to find all bridges and articulation points in the graph
void findBridgesAndArticulationPoints(int n, int m, Edge edges[], int *bridges, int *articulationPoints) {
    // Create an adjacency list representation of the graph
    int **adj = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        adj[i] = (int *)malloc(m * sizeof(int));
    }
    for (int i = 0; i < m; i++) {
        adj[edges[i].u][edges[i].v] = 1;
        adj[edges[i].v][edges[i].u] = 1;
    }

    // Perform DFS to find all bridges and articulation points
    int *visited = (int *)malloc(n * sizeof(int));
    int *low = (int *)malloc(n * sizeof(int));
    int *disc = (int *)malloc(n * sizeof(int));
    int *parent = (int *)malloc(n * sizeof(int));
    int time = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(i, -1, adj, visited, low, disc, parent, &time, bridges, articulationPoints);
        }
    }

    // Free memory
    for (int i = 0; i < n; i++) {
        free(adj[i]);
    }
    free(adj);
    free(visited);
    free(low);
    free(disc);
    free(parent);
}

// Function to perform DFS
void dfs(int u, int parent, int **adj, int *visited, int *low, int *disc, int *parentArray, int *time, int *bridges, int *articulationPoints) {
    visited[u] = 1;
    disc[u] = *time;
    low[u] = *time;
    (*time)++;
    int children = 0;
    for (int v = 0; v < n; v++) {
        if (adj[u][v]) {
            if (!visited[v]) {
                parentArray[v] = u;
                children++;
                dfs(v, u, adj, visited, low, disc, parentArray, time, bridges, articulationPoints);
                low[u] = min(low[u], low[v]);
                if (parent == -1 && children > 1) {
                    articulationPoints[u] = 1;
                } else if (parent != -1 && low[v] > disc[u]) {
                    bridges[u * n + v] = 1;
                    bridges[v * n + u] = 1;
                }
            } else if (v != parent) {
                low[u] = min(low[u], disc[v]);
            }
        }
    }
}

// Function to find the minimum number of shields required
int findMinShields(int n, int m, Edge edges[], int k) {
    int *bridges = (int *)malloc(n * n * sizeof(int));
    int *articulationPoints = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        articulationPoints[i] = 0;
    }
    for (int i = 0; i < n * n; i++) {
        bridges[i] = 0;
    }
    findBridgesAndArticulationPoints(n, m, edges, bridges, articulationPoints);
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (articulationPoints[i]) {
            count++;
        }
    }
    free(bridges);
    free(articulationPoints);
    return count * k;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
        Edge *edges = (Edge *)malloc(m * sizeof(Edge));
        for (int i = 0; i < m; i++) {
            scanf("%d %d", &edges[i].u, &edges[i].v);
        }
        int minShields = findMinShields(n, m, edges, k);
        printf("%d\n", minShields);
        free(edges);
    }
    return 0;
}

