// COMPLETE, COMPILABLE C++ code
#include <iostream>
#include <vector>
using namespace std;

// Structure to represent a graph edge
struct Edge {
    int u, v;
};

// Function to find all bridges and articulation points in the graph
void findBridgesAndArticulationPoints(int n, int m, Edge edges[], vector<int> &bridges, vector<int> &articulationPoints) {
    // Create an adjacency list representation of the graph
    vector<vector<int>> adj(n);
    for (int i = 0; i < m; i++) {
        adj[edges[i].u].push_back(edges[i].v);
        adj[edges[i].v].push_back(edges[i].u);
    }

    // Perform DFS to find all bridges and articulation points
    vector<int> visited(n, 0);
    vector<int> low(n, 0);
    vector<int> disc(n, 0);
    vector<int> parent(n, -1);
    int time = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(i, -1, adj, visited, low, disc, parent, time, bridges, articulationPoints);
        }
    }
}

// Function to perform DFS
void dfs(int u, int parent, vector<vector<int>> &adj, vector<int> &visited, vector<int> &low, vector<int> &disc, vector<int> &parentArray, int &time, vector<int> &bridges, vector<int> &articulationPoints) {
    visited[u] = 1;
    disc[u] = time;
    low[u] = time;
    time++;
    int children = 0;
    for (int v : adj[u]) {
        if (!visited[v]) {
            parentArray[v] = u;
            children++;
            dfs(v, u, adj, visited, low, disc, parentArray, time, bridges, articulationPoints);
            low[u] = min(low[u], low[v]);
            if (parent == -1 && children > 1) {
                articulationPoints[u] = 1;
            } else if (parent != -1 && low[v] > disc[u]) {
                bridges[u * adj.size() + v] = 1;
                bridges[v * adj.size() + u] = 1;
            }
        } else if (v != parent) {
            low[u] = min(low[u], disc[v]);
        }
    }
}

// Function to find the minimum number of shields required
int findMinShields(int n, int m, Edge edges[], int k) {
    vector<int> bridges(n * n, 0);
    vector<int> articulationPoints(n, 0);
    findBridgesAndArticulationPoints(n, m, edges, bridges, articulationPoints);
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (articulationPoints[i]) {
            count++;
        }
    }
    return count * k;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n, m, k;
        cin >> n >> m >> k;
        Edge *edges = new Edge[m];
        for (int i = 0; i < m; i++) {
            cin >> edges[i].u >> edges[i].v;
        }
        int minShields = findMinShields(n, m, edges, k);
        cout << minShields << endl;
        delete[] edges;
    }
    return 0;
}

